#include <bits/stdc++.h>
using namespace std;
int n,k,a[10];
void dfs(int pos){
    if(pos==n+1){
        for(int i=1;i<=n;i++)
            cout<<a[i]<<' ';
        cout<<endl;
        return;
    }
    for(int i=1;i<=k;i++) {
        a[pos]=i;
        dfs(pos+1);
    }
}
int main(void) {
    cin>>n>>k;
    dfs(1);
    return false;
}
